<?php
// 1. Allow Cross-Origin Requests
header("Access-Control-Allow-Origin: *");
header("Access-Control-Allow-Methods: POST, OPTIONS");
header("Access-Control-Allow-Headers: *");

if ($_SERVER['REQUEST_METHOD'] === 'OPTIONS') {
    http_response_code(200);
    exit;
}

// 2. Safely grab the payload
$json = isset($_POST['payload']) ? $_POST['payload'] : file_get_contents('php://input');
$data = json_decode($json, true);

if (!$data) {
    // Return 200 instead of 400 to prevent strict web hosts from dropping the JSON body
    http_response_code(200);
    echo json_encode(["result" => "error", "message" => "No data received. Payload was empty."]);
    exit;
}

