// 4. SECURE SERVER-SIDE GRADING
$score = 0;
$totalQuestions = isset($data['total']) ? (int)$data['total'] : 0;

if (isset($data['answers']) && is_array($data['answers'])) {
    foreach ($data['answers'] as $ans) {
        $qText = trim($ans['question']);
        $studentAnswer = trim($ans['selected']);
        
        // If the question exists in our key and the answer matches exactly
        if (isset($masterKey[$qText]) && $masterKey[$qText] === $studentAnswer) {
            $score++;
        }
    }
}

// Calculate true percentage
$percentageNum = ($totalQuestions > 0) ? round(($score / $totalQuestions) * 100) : 0;
$percentageStr = $percentageNum . "%";

// 5. Set CSV file name for Summative
$csvFile = 'summative_results.csv';
$fileExisted = file_exists($csvFile);

// CRITICAL FIX: Use @ to suppress PHP's default crash warning so we can handle the error cleanly
$file = @fopen($csvFile, 'a');

// If the server blocked us from opening the file (Permissions issue), return a clean JSON error
if ($file === false) {
    // By returning a 200 status instead of a 500, we prevent the web host from intercepting 
    // the error and stripping out the JSON body, ensuring the JS can display this message.
    http_response_code(200); 
    echo json_encode([
        "result" => "error", 
        "message" => "Server Permission Denied. PHP cannot write to the CSV file. Please change the file/folder permissions to 755 or 666."
    ]);
    exit;
}

// 6. Exactly 9 Headers (WITH NOTES)
if (!$fileExisted) {
    fputcsv($file, ['Timestamp', 'Last Name', 'First Name', 'Class', 'Chapter', 'Score', 'Total', 'Percentage', 'Notes Used']);
}

date_default_timezone_set('America/Los_Angeles'); 
$timestamp = date('m/d/Y H:i:s');

// 7. Build Row Data using the SERVER GRADED score
$row = [
    $timestamp,
    isset($data['lastName']) ? $data['lastName'] : '',
    isset($data['firstName']) ? $data['firstName'] : '',
    isset($data['studentClass']) ? $data['studentClass'] : '',
    isset($data['chapter']) ? $data['chapter'] : '',
    $score,           // <-- Real Score
    $totalQuestions,
    $percentageStr,   // <-- Real Percentage
    isset($data['notesUrl']) ? $data['notesUrl'] : 'No Notes Used'
];

// 8. Write and Close
if (fputcsv($file, $row)) {
    fclose($file);
    // Echo the REAL score back to the Javascript so the UI updates
    echo json_encode([
        "result" => "success", 
        "message" => "Saved",
        "score" => $score,
        "total" => $totalQuestions,
        "percentage" => $percentageNum
    ]);
} else {
    fclose($file);
    http_response_code(200); // Prevent host hijack
    echo json_encode(["result" => "error", "message" => "Opened file but failed to write row."]);
}
